pub const GENERATED_INTRINSIC_ABI: u32 = 1;
pub const GENERATED_INTRINSIC_ABI_NAMESPACE: &str = "__cuda_oxide_intrinsic_abi_v1";

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum RawIntrinsicIdentity {
    NotRawCrate,
    Known(String),
    UnsupportedAbi(String),
    UnknownId(String),
}

/// Classify the unrewritten raw intrinsic DefPath. rustc's ordinary name
/// printer may prefer a public re-export path, which is source API rather than ABI.
pub fn classify_raw_intrinsic(fn_def: FnDef) -> RawIntrinsicIdentity {
    let crate_name = fn_def.krate().name.to_string();
    if !matches!(crate_name.as_str(), "cuda_intrinsics" | "cuda-intrinsics") {
        return RawIntrinsicIdentity::NotRawCrate;
    }

    let mut segments = Vec::new();
    let mut current = Some(fn_def.def_id());
    while let Some(def_id) = current {
        let printed = def_id.name();
        let segment = printed.as_str().rsplit("::").next().unwrap_or_default();
        if segment != crate_name {
            segments.push(segment.to_owned());
        }
        current = def_id.parent();
    }
    segments.reverse();
    classify_raw_intrinsic_path(
        &crate_name,
        format!("{crate_name}::{}", segments.join("::")),
    )
}

fn classify_raw_intrinsic_path(crate_name: &str, path: String) -> RawIntrinsicIdentity {
    if !matches!(crate_name, "cuda_intrinsics" | "cuda-intrinsics") {
        return RawIntrinsicIdentity::NotRawCrate;
    }
    if is_raw_generated_intrinsic_path(&path) {
        return RawIntrinsicIdentity::Known(path);
    }
    let namespace = path.split("::").nth(1).unwrap_or_default();
    if namespace.starts_with("__cuda_oxide_intrinsic_abi_v")
        && namespace != GENERATED_INTRINSIC_ABI_NAMESPACE
    {
        RawIntrinsicIdentity::UnsupportedAbi(path)
    } else {
        RawIntrinsicIdentity::UnknownId(path)
    }
}

pub fn require_supported_raw_intrinsic(
    fn_def: FnDef,
    loc: &Location,
) -> TranslationResult<Option<String>> {
    match classify_raw_intrinsic(fn_def) {
        RawIntrinsicIdentity::NotRawCrate => Ok(None),
        RawIntrinsicIdentity::Known(path) => Ok(Some(path)),
        RawIntrinsicIdentity::UnsupportedAbi(path) => input_err!(
            loc.clone(),
            TranslationErr::unsupported(format!(
                "cuda-intrinsics ABI mismatch: `{path}` uses an unsupported intrinsic ABI; this compiler supports ABI v{GENERATED_INTRINSIC_ABI}"
            ))
        ),
        RawIntrinsicIdentity::UnknownId(path) => input_err!(
            loc.clone(),
            TranslationErr::unsupported(format!(
                "cuda-intrinsics ABI mismatch: `{path}` is not a known intrinsic ID in ABI v{GENERATED_INTRINSIC_ABI}"
            ))
        ),
    }
}

