    #[test]
    fn raw_intrinsic_identity_classification_fails_closed() {
        assert_eq!(
            classify_raw_intrinsic_path("serde", "serde::helper".into()),
            RawIntrinsicIdentity::NotRawCrate
        );
        assert!(matches!(
            classify_raw_intrinsic_path(
                "cuda_intrinsics",
                "cuda_intrinsics::__cuda_oxide_intrinsic_abi_v2::i0001".into()
            ),
            RawIntrinsicIdentity::UnsupportedAbi(_)
        ));
        assert!(matches!(
            classify_raw_intrinsic_path(
                "cuda_intrinsics",
                "cuda_intrinsics::__cuda_oxide_intrinsic_abi_v1::i9999".into()
            ),
            RawIntrinsicIdentity::UnknownId(_)
        ));
        assert!(matches!(
            classify_raw_intrinsic_path("cuda_intrinsics", "cuda_intrinsics::helper".into()),
            RawIntrinsicIdentity::UnknownId(_)
        ));
    }
